mapper.select:
    	/* com.erns.coching.common.file.mapper.FileDAO.getList */

    	SELECT B.* FROM (
			SELECT A.*,ROW_NUMBER() OVER () AS RN, COUNT(*) OVER() TOTAL FROM (
				SELECT

				FROM T_FILE_INF AA


					AND AA.DEL_YN = 'N'

			) A
		) B

	    	WHERE RN BETWEEN (#{offset} + 1) AND #{offset} + #{rowSize}

/* com.erns.coching.common.file.mapper.FileDAO.getListCount */
SELECT COUNT(*) FROM T_FILE_INF AA
AND AA.DEL_YN = 'N'

/* com.erns.coching.common.file.mapper.FileDAO.selectByRefId */

SELECT

FROM T_FILE_INF AA

	AND AA.REF_CODE = #{refCode	, jdbcType=VARCHAR}
	AND AA.REF_SEQ 	= #{refSeq	, jdbcType=INTEGER}
	AND AA.DEL_YN 	= 'N'

ORDER BY AA.SORT_ORD

    	/* com.erns.coching.common.file.mapper.FileDAO.load */

    	SELECT

		FROM T_FILE_INF AA

			AND AA.FILE_ID = #{fileId , jdbcType=VARCHAR}

    	/* com.erns.coching.common.file.mapper.FileDAO.loadVo */

    	SELECT

			FROM T_FILE_INF AA

				AND AA.FILE_ID = #{fileId , jdbcType=VARCHAR}

mapper.insert:
    	/* com.erns.coching.common.file.mapper.FileDAO.insert */


			SELECT encode((nextval('seq_t_file_inf')::varchar(255))::bytea, 'base64')


    	INSERT INTO T_FILE_INF (
    		  FILE_ID
			, REF_CODE
			, REF_SEQ
			, SORT_ORD
			, FILE_NAME
			, FILE_EXT
			, FILE_NAME_DEST
			, FILE_PATH
			, FILE_SIZE
			, DEL_YN

			, RGTR
			, RGT_DTTM
			, CHNR
			, CHNG_DTTM
    	) VALUES (
			  #{fileId		, jdbcType=VARCHAR}
			, #{refCode		, jdbcType=VARCHAR}
			, #{refSeq		, jdbcType=INTEGER}
			, (
				SELECT COALESCE(MAX(ZZ.SORT_ORD), 0) +1
				FROM T_FILE_INF ZZ
				WHERE ZZ.REF_CODE = #{refCode, jdbcType=VARCHAR}
				AND   ZZ.REF_SEQ  = #{refSeq , jdbcType=INTEGER}
			)
			, #{fileName	, jdbcType=VARCHAR}
			, #{fileExt		, jdbcType=VARCHAR}
			, #{fileNameDest, jdbcType=VARCHAR}
			, #{filePath	, jdbcType=VARCHAR}
			, #{fileSize	, jdbcType=INTEGER}
			, COALESCE(#{delYn	, jdbcType=CHAR}, 'N')

			, #{rgtr		, jdbcType=INTEGER}
			, now()
			, #{chnr		, jdbcType=INTEGER}
			, now()
    	)

mapper.update:
    	/* com.erns.coching.common.file.mapper.FileDAO.update */

    	UPDATE T_FILE_INF SET
			  REF_CODE       = #{refCode		, jdbcType=VARCHAR}
			, REF_SEQ        = #{refSeq			, jdbcType=INTEGER}
			, FILE_NAME      = #{fileName		, jdbcType=VARCHAR}
			, FILE_EXT       = #{fileExt		, jdbcType=VARCHAR}
			, FILE_NAME_DEST = #{fileNameDest	, jdbcType=VARCHAR}
			, FILE_PATH      = #{filePath		, jdbcType=VARCHAR}
			, FILE_SIZE      = #{fileSize		, jdbcType=INTEGER}
			, DEL_YN         = COALESCE(#{delYn		, jdbcType=CHAR}, 'N')

			, CHNR 			 = #{chnr	, jdbcType=INTEGER}
			, CHNG_DTTM 	 = now()

			AND FILE_ID 	 = #{fileId, jdbcType=VARCHAR}

/* com.erns.coching.common.file.mapper.FileDAO.updateDelYn */

UPDATE T_FILE_INF SET
	DEL_YN 		= #{delYn, jdbcType=CHAR}

	, CHNR 		= #{chnr	, jdbcType=INTEGER}
	, CHNG_DTTM = now()

	AND FILE_ID = #{fileId, jdbcType=VARCHAR}

/* com.erns.coching.common.file.mapper.FileDAO.updateDelYnByRefId */

UPDATE T_FILE_INF SET
	DEL_YN 		= #{delYn	, jdbcType=CHAR}

	, CHNR 		= #{chnr	, jdbcType=INTEGER}
	, CHNG_DTTM = now()

	AND REF_CODE = #{refCode, jdbcType=VARCHAR}
	AND REF_SEQ  = #{refSeq , jdbcType=INTEGER}

/* com.erns.coching.common.file.mapper.FileDAO.updateOrder */

UPDATE T_FILE_INF SET
	SORT_ORT 	= #{fileOrder, jdbcType=INTEGER}

	, CHNR 		= #{chnr	 , jdbcType=INTEGER}
	, CHNG_DTTM = now()

	AND FILE_ID = #{fileId   , jdbcType=VARCHAR}

mapper.delete:
/* com.erns.coching.common.file.mapper.FileDAO.deleteByRefId */

DELETE FROM T_FILE_INF

	AND REF_CODE = #{refCode, jdbcType=VARCHAR}
	AND REF_SEQ  = #{refSeq, jdbcType=INTEGER}

mapper.update:
/* com.erns.coching.common.file.mapper.FileDAO.updateRefSeq */

UPDATE T_FILE_INF SET
	REF_SEQ 	= #{refSeq, jdbcType=INTEGER}

	, CHNR 		= #{chnr	 , jdbcType=INTEGER}
	, CHNG_DTTM = now()

	AND FILE_ID = #{fileId   , jdbcType=VARCHAR}

mapper.select:
    	/* com.erns.coching.common.file.mapper.FileDAO.getWillRemovePreviewFiles */

    	SELECT 

			FROM T_FILE_INF AA
			WHERE 
				AA.ref_code = 'FT_PREVIEW'
				AND AA.rgt_dttm::date < CURRENT_DATE - INTERVAL '2 days';
